const browser = await chromium.launch();
const page = await browser.newPage();
await page.goto('http://localhost:3000', { waitUntil: 'networkidle' });
await page.waitForTimeout(2000);

// Check the fixed structure
const structure = await page.evaluate(() => {
  const bodyStyle = window.getComputedStyle(document.body);
  const htmlClasses = document.documentElement.className;

  // Sample some key elements
  const samples = [];
  const selectors = [
    'a.text-lg',           // "aitrace" logo
    'button',              // filter buttons
    'span.text-sm',        // commit messages
    'code',                // commit hashes
    'h3',                  // date headers
  ];

  for (const sel of selectors) {
    const el = document.querySelector(sel);
    if (!el) continue;
    const style = window.getComputedStyle(el);
    let bgEl = el;
    let bgColor = style.backgroundColor;
    while (bgEl && (bgColor === 'rgba(0, 0, 0, 0)' || bgColor === 'transparent')) {
      bgEl = bgEl.parentElement;
      if (bgEl) bgColor = window.getComputedStyle(bgEl).backgroundColor;
    }
    samples.push({
      selector: sel,
      text: el.innerText?.slice(0, 40),
      color: style.color,
      bg: bgColor,
    });
  }

  return {
    htmlClasses,
    bodyBg: bodyStyle.backgroundColor,
    bodyColor: bodyStyle.color,
    samples,
  };
});

console.log('html classes:', structure.htmlClasses);
console.log('body bg:', structure.bodyBg);
console.log('body color:', structure.bodyColor);
console.log('\nSamples:');
for (const s of structure.samples) {
  console.log(`  ${s.selector}: "${s.text}" | color: ${s.color} | bg: ${s.bg}`);
}

// Quick contrast check
const issues = await page.evaluate(() => {
  const parseRGB = (c) => {
    const m = c.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
    return m ? [+m[1], +m[2], +m[3]] : null;
  };
  const lum = ([r, g, b]) => {
    const s = (v) => { v /= 255; return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4); };
    return 0.2126 * s(r) + 0.7152 * s(g) + 0.0722 * s(b);
  };

  let count = 0;
  const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
  const seen = new Set();
  while (walker.nextNode()) {
    const el = walker.currentNode.parentElement;
    if (!el || seen.has(el) || !walker.currentNode.textContent?.trim()) continue;
    seen.add(el);
    const rect = el.getBoundingClientRect();
    if (rect.width === 0 || rect.height === 0) continue;

    const style = window.getComputedStyle(el);
    const fg = parseRGB(style.color);
    let bgEl = el, bgStr = style.backgroundColor;
    while (bgEl && (bgStr === 'rgba(0, 0, 0, 0)' || bgStr === 'transparent')) {
      bgEl = bgEl.parentElement;
      if (bgEl) bgStr = window.getComputedStyle(bgEl).backgroundColor;
    }
    const bg = parseRGB(bgStr);

    if (fg && bg) {
      const l1 = lum(fg), l2 = lum(bg);
      const ratio = (Math.max(l1, l2) + 0.05) / (Math.min(l1, l2) + 0.05);
      if (ratio < 2.5) count++;
    }
  }
  return count;
});

console.log(`\nLow contrast elements (ratio < 2.5): ${issues}`);
console.log(issues === 0 ? 'PASS: No contrast issues!' : `FAIL: ${issues} elements with poor contrast`);

await browser.close();
