      </div>

      {/* Agent breakdown */}
      <Card>
        <CardHeader>
          <CardTitle className="text-sm font-mono">Sessions by Agent</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {Object.entries(stats.by_agent).map(([agent, count]) => {
            const config = AGENT_LABELS[agent] ?? { label: agent, color: "bg-zinc-500" };
            const pct = totalByAgent > 0 ? (count / totalByAgent) * 100 : 0;
            return (
              <div key={agent} className="space-y-1">
                <div className="flex justify-between text-sm">
                  <span>{config.label}</span>
                  <span className="font-mono text-muted-foreground">{count} ({Math.round(pct)}%)</span>
                </div>
                <div className="h-2 rounded-full bg-muted overflow-hidden">
                  <div
                    className={`h-full rounded-full ${config.color}`}
                    style={{ width: `${pct}%` }}
                  />
                </div>
              </div>
            );
          })}
        </CardContent>
      </Card>

      {/* Link breakdown */}
      <Card>
        <CardHeader>
          <CardTitle className="text-sm font-mono">Link Status</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-3 gap-4 text-center">
            <div>
