	messages := session.Messages
	var entries []model.TimelineEntry

	for i, mc := range commits {
		var startIdx, endIdx int

		if i == 0 {
			// First commit: messages from session start to this commit's timestamp
			startIdx = 0
		} else {
			// Messages after the previous commit's timestamp
			prevCommitTime := commits[i-1].commit.Timestamp
			startIdx = findMessageIndexAfter(messages, prevCommitTime)
		}

		if i == len(commits)-1 {
			// Last commit: messages up to session end
			endIdx = len(messages)
		} else {
			// Messages up to and including this commit's timestamp
			endIdx = findMessageIndexAfter(messages, mc.commit.Timestamp)
		}

		// Ensure valid range
		if startIdx > len(messages) {
			startIdx = len(messages)
		}
		if endIdx > len(messages) {
			endIdx = len(messages)
		}
		if endIdx < startIdx {
			endIdx = startIdx
		}

		c := *mc.commit
		s := *session
		entries = append(entries, model.TimelineEntry{
			Commit:          &c,
			Session:         &s,
			LinkConfidence:  mc.confidence,
			MessageStartIdx: startIdx,
			MessageEndIdx:   endIdx,
		})
	}

	return entries
}"}

