func runStatus(cmd *cobra.Command, args []string) error {
	absDir, err := filepath.Abs(statusProjectDir)
	if err != nil {
		return err
	}

	fmt.Printf("Project: %s\n\n", absDir)

	parsers := parser.AllParsers()
	total := 0

	for _, p := range parsers {
		files, err := p.Detect(absDir)
		if err != nil {
